import { mapState } from "vuex";
export default {
  props: {
    champion: Object
  },
  methods: {
    selectedChampion() {
      this.$socket.sendChampSelectMessage("CHAMPSELECT_SELECT_CHAMPION", {
        data: this.champion.id
      }, (response, error) => {
        if (error) {
          console.log("Flyback error:");
          console.log(error);
        }
        this.$sound.template("CHAMPION_GRID_CLICK");
        console.log("SELECTED CHAMPION " + this.champion.id);
      });
    },
    selectedBan() {
      this.$socket.sendChampSelectMessage("CHAMPSELECT_BAN_SELECT_CHAMPION", {
        data: this.champion.id
      }, (response, error) => {
        if (error) {
          console.log("Flyback error:");
          console.log(error);
        }
        this.$sound.template("CHAMPION_GRID_CLICK");
        console.log("SELECTED BAN " + this.champion.id);
      });
    },
    getChampionImgUrl() {
      const {
        host,
        port
      } = this.$store.state.config.download;
      return `${host}:${port}/champions/${this.champion.id}.jpg`;
    }
  },
  computed: mapState({
    currentPlayer: state => state.csCurrentPlayer,
    globalState: state => state.csGlobalState,
    isBanned(state) {
      if ([...state.csAllyBans, ...state.csEnemyBans].filter(ban => {
        return ban.id == this.champion.id;
      }).length > 0) {
        return true;
      } else {
        return false;
      }
    }
  })
};
